from google.cloud import storage
from google.cloud import firestore
import os
import pubsub

def process_files(data, context):
    bucket_name = data['bucket']
    file_name = data['name']

    # Get the object from Cloud Storage
    client = storage.Client()
    blob = client.bucket(bucket_name).blob(file_name)

    # Download file from Cloud Storage to /tmp/
    download_path = f"/tmp/{file_name}"
    blob.download_to_filename(download_path)

    # Process the data (in this example, just print it)
    with open(download_path) as f:
        contents = f.read()

    # Write data to Firestore
    db = firestore.Client()
    doc_ref = db.collection('data').document(file_name)
    doc_ref.set({'file_contents': contents})

    # Publish message to Pub/Sub
    publisher = pubsub.PublisherClient()
    topic_path = 'your-project-id/topics/your-topic-name'
    message_id = publisher.publish(topic_path, data=b'Hello, World!')

    print(f'Published a message: {message_id}')

